  ('aboriginal-5ff21eeb-moex-00208', 'aboriginal-5ff21eeb', 'aboriginal-5ff21eeb-moex-111-6ed013db', 'sub-aboriginal-5ff21eeb-02', NULL, 'single_choice', 'Whatisthenatureofthispassage?', '["Descriptive", "Contrastive", "Argumentative", "Persuasive"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:13+00:00", "source_pdf_sha1": "80ae72992682", "answer_pdf_sha1": "09be54dfa1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "506", "s": "0221", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('aboriginal-5ff21eeb-moex-00209', 'aboriginal-5ff21eeb', 'aboriginal-5ff21eeb-moex-110-9b7ab1bb', 'sub-aboriginal-5ff21eeb-01', NULL, 'essay', '甲將其所有價值500 萬元之 A屋供乙設定普通抵押權，以擔保乙對甲之
200 萬元債權。其後，甲將設定有上述抵押權之A屋，以 300萬元出賣
予丙。未料於甲應交付 A屋予丙、並為移轉登記之履行期屆至前，因鄰
居丁處發生火災，致 A 屋遭延燒而滅失（A 屋滅失時之價值為 600 萬
元），甲乃基於侵權行為之規定，請求丁賠償甲因此所受損害。試問：乙、
丙就甲對丁所取得之損害賠償請求權，各得為如何之主張？乙、丙對甲
所取得之權利的主張其優劣次序如何？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:13+00:00", "source_pdf_sha1": "17a8c663fd9d", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "0801", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('aboriginal-5ff21eeb-moex-00210', 'aboriginal-5ff21eeb', 'aboriginal-5ff21eeb-moex-110-9b7ab1bb', 'sub-aboriginal-5ff21eeb-01', NULL, 'essay', '甲死亡後，其遺產由其配偶乙及子女丙、丁繼承。遺產中之不動產部分，
於辦妥繼承登記後，基於乙之請求，與丙、丁達成協議各自分得部分，
但卻遲未基於該協議辦理分割登記。事經二十年後，丁因病死亡，其遺
產由戊繼承。戊乃請求乙、丙依與丁之前述協議，偕同出面辦理分割登
記，詎料戊之請求遭丙拒絕。丙之拒絕是否有理？戊有無得打破此僵局
之救濟方法？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:13+00:00", "source_pdf_sha1": "17a8c663fd9d", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "0801", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('aboriginal-5ff21eeb-moex-00211', 'aboriginal-5ff21eeb', 'aboriginal-5ff21eeb-moex-110-9b7ab1bb', 'sub-aboriginal-5ff21eeb-01', NULL, 'single_choice', '甲欲透過email贈與乙A書，甲寫妥該封email後，於傳送前，甲因臨時有急事外出而未送出， 後其同居之友人丙借用其電腦，順手將該封信傳送出去。下列敘述，何者正確？', '["甲贈與乙A書之意思表示於email寫妥時，視為已發出", "甲贈與乙A書之意思表示於丙傳送到乙時發生效力", "甲得撤銷該贈與A書之意思表示", "甲應對乙之信賴利益損害，負賠償之責"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:13+00:00", "source_pdf_sha1": "17a8c663fd9d", "answer_pdf_sha1": "7e5cdb5cd90a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅法務"}'::jsonb, NULL)
